var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"우승을 축하드립니다! 멋진 경기로 드림 네버 랜드에 즐거움을 선사해 주셨어요!","JPN":"優勝、おめでとうございます！　素晴らしい試合でドリームネバーランドに楽しさをプレゼントしてくださいましたね！","ENG":"You win! Congratulations! Your winning match has brought joy to Dream Neverland!","TWN":"恭喜獲勝！謝謝你們為夢幻樂園帶來這麼精彩的比賽！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"엣헴! 우리의 승리다, 루루 조리장!","JPN":"えっへん！　私たちの勝利だぞ、ルル調理長！","ENG":"Ahem! Chef Lulu, we won!","TWN":"嘿嘿！我們贏咧，露露料理長！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"만세~","JPN":"バンザ～イ！","ENG":"Yippee!","TWN":"萬歲～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"역시……! 수영장에는 열정의 발리볼이지!","JPN":"やっぱり……！　プールでは情熱のバレーボールだよね！","ENG":"I knew it...! Every pool needs some volleyball action!","TWN":"果然……！游泳池就是要玩熱情的排球！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"태양과 가장 가까이 있는 헤이븐 랜드에 딱 맞는 스포츠야!","JPN":"太陽ともっとも近いところにあるヘイブンランドにピッタリのスポーツだよ！","ENG":"It's the perfect sport for Havenland, the place closest to the sun!","TWN":"離太陽最近的天堂樂園最適合這種運動！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"앗, 차가워!","JPN":"あっ、冷てっ！","ENG":"Hey! That's cold!","TWN":"哇，好冷！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"하하! 시그마 선장님의 물대포 맛을 보지 않으려면 너도 얼른 수영장에 들어와야 할 거야!","JPN":"はは！　シグマ船長の水鉄砲を味わいたくなかったら、早くプールに入りたまえ！","ENG":"Haha! If you don't want Captain Sigma's water cannons blasting at you, then get in the water quick!","TWN":"哈哈！要是不想被西格瑪船長的水砲攻擊，就趕快進到游泳池來！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"옷 다 젖겠어!","JPN":"服が全部濡れちゃうよ！","ENG":"My clothes are getting all wet!","TWN":"衣服會濕掉啦！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"요호호! 해적 전투다!!","JPN":"ヨホホ！　海賊戦闘だ！！","ENG":"Yo ho ho! It's a pirate's battle for me!!","TWN":"哇哈哈！海盜開戰！！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"다치지 않게 조심해?","JPN":"怪我しないように気をつけて。","ENG":"Be careful not to hurt yourself, okay?","TWN":"小心不要受傷喔。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"걱정 마! 선장님은 절대로 안 다치니까!","JPN":"心配しないで！　船長は絶対に怪我しないから！","ENG":"Don't worry! The captain never gets hurt!","TWN":"放心！船長是絕對不會受傷的！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"이판사판이다!! 덤벼라, 시그마 선장! 본때를 보여주지!","JPN":"一か八かだ！！　かかってこい、シグマ船長！　目に物見せてやる！","ENG":"It's all or nothing! Bring it, Captain Sigma! I'll show you who's boss!","TWN":"濕就濕吧！放馬過來吧，西格瑪船長！看我的厲害！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"요호호!","JPN":"ヨホホ！","ENG":"Yo ho ho!","TWN":"哇哈哈！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저걸 잘 놀아준다고 해야 하나, 정신 연령이 비슷하다고 해야 하나.","JPN":"あれって遊んであげてるっていうのかな、それとも精神年齢が同じというべき？","ENG":"I dunno if he's just good with kids, or if he's a kid himself...","TWN":"該說他很會陪小朋友玩嗎？該說他們的心智年齡很接近嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 여기 있었네. 너희들이 이번 우승자야?","JPN":"あ、いたいた。あんたたちが今回の優勝者？","ENG":"Oh, there you are. Are you the winners?","TWN":"喔，原來在這裡，你們是這次的贏家嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"이 구역 담당자인 호란이다.","JPN":"この区域の担当者、ホランよ。","ENG":"I'm Horan, the one who's in charge of this place.","TWN":"我是這個區域的負責人 小蘭。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"호란 님?! 맙소사, 진짜 호란 님이야! 헤이븐 랜드를 개조한 최고의 엔지니어!","JPN":"ホラン様！？　うわ、本物のホラン様だ！　ヘイブンランドを改造した最高のエンジニア！","ENG":"Ms. Horan?! No way! It's really you! The greatest engineer who literally recreated Havenland!","TWN":"小蘭？！我的天，真的是小蘭！改造天堂樂園的最強工程師！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"야. 호들갑 좀 그만 떨어.","JPN":"ちょっと。大げさすぎじゃない？","ENG":"Geez, will you quit with your fangirling?","TWN":"好了啦，不要一直長他人志氣。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……그래. 어쨌거나 우리에겐 넘어서야 할 상대야.","JPN":"……うん。とにかく越えなきゃならない相手だ。","ENG":"...Yeah. She's still another obstacle we have to beat.","TWN":"……沒錯，總之她就是我們必須跨越的對手。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"크흐. 당당한데.","JPN":"くう。いい度胸だね。","ENG":"Ooh. I like your style, kid.","TWN":"呵呵，口氣很大喔。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"경기 내용은 전해 들었어. 파죽지세로 이겼다지?","JPN":"試合の内容は聞いたよ。破竹の勢いで勝ったらしいじゃないの。","ENG":"I heard about the match. You crushed them, didn't you?","TWN":"我有聽說你們的事蹟，一路勢如破竹地贏過來對吧？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그럼! 시그마 해적단이 오늘 이 배를 손에 넣을 테니까!","JPN":"そうだよ！　シグマ海賊団が今日この船を手に入れるんだから！","ENG":"Yup! This ship will soon be in the hands of the Sigma Pirates!","TWN":"那當然！今天西格瑪海盜團要拿下這艘船！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"시그마! 간부님 앞에서 대놓고 그렇게 말하면……!","JPN":"シグマ！　幹部のまえでそんなに堂々と喋ったら……！","ENG":"Sigma! You can't say that in front of her...!","TWN":"西格瑪！對幹部說話不可以這樣沒大沒小……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"아냐. 헤이븐 랜드를 손에 넣으려면 배짱이 있어야지.","JPN":"いや。ヘイブンランドを手に入れるためには度胸が必要だ。","ENG":"No, it's fine. You need guts like that to become the new owner of Havenland.","TWN":"不會，要拿下天堂樂園就要有那種膽量。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"자, 그렇다는 말은 물어볼 필요도 없이 내게 도전하겠다는 뜻이렷다?","JPN":"さて、ということは聞くまでもなく私に挑戦するという意味よね？","ENG":"Well then, are you here to challenge me or what?","TWN":"來吧，那我也無需多問，你們要挑戰我對吧？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……물론이야. 우리에겐 너희들을 쓰러뜨려야 할 이유가 있거든.","JPN":"……もちろんだよ。あんたたちを倒さないといけない理由があるからね。","ENG":"Of course. We have a reason to take you down.","TWN":"……沒錯，我們有必須打倒你的理由。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"오호라…….","JPN":"ほう……","ENG":"Ho-oh...","TWN":"呵呵……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"좋아. 거두절미하고 바로 본론으로 들어가지.","JPN":"よし。それではすぐ本題に入ろう。","ENG":"All right! Then let's get started right away.","TWN":"好，那就廢話不多說，直接進入正題吧！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"도전 종목은 간단해. 바로…….","JPN":"挑戦種目は簡単よ。それは……","ENG":"This challenge is simple. It's...","TWN":"挑戰內容很簡單，就是……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"술 대결이다!","JPN":"酒飲み対決！","ENG":"A booze duel!","TWN":"喝酒比賽！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L42_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"술?","JPN":"お酒？","ENG":"Booze?","TWN":"喝酒？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"그래. 거추장스러운 규칙 없이, 누가 더 많이 마시나 승부란 거야.","JPN":"そう。面倒なルールなし。より多く飲めた方が勝ちよ。","ENG":"Yup. No fancy-shmancy rules. Whoever can drink the most wins.","TWN":"正是，沒有複雜的規則，誰喝的多誰就贏！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"나! 나! 내가 할래! 해적 선장님은 럼주를 물처럼 마실 수 있어!","JPN":"私！　私！　私がやる！　海賊の船長はラム酒を水のように飲めるんだよ！","ENG":"Me! Me! I wanna play! Captain Sigma can drink rum like it's water!","TWN":"選我選我！我來！海盜船長可以把蘭姆酒當水喝的！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"넌 안 돼. 절대 안 돼.","JPN":"アンタはダメ。絶対ダメ。","ENG":"Nope. Absolutely not.","TWN":"不可以，你不行。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"그래. 참고로 미성년자들은 도전 금지야.","JPN":"ちなみに未成年者は挑戦禁止。","ENG":"She's right. No minors are allowed to play.","TWN":"對啊，提醒一下，未成年是禁止參賽的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"정 나설 사람이 없으면 다른 어른이라도 데려오라고.","JPN":"出場できる人がいないなら、他の大人でも連れておいで。","ENG":"If there's no one on your team, you can find some other adult to help you out.","TWN":"沒人可以參加的話，就找其他大人來吧。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"치이…….","JPN":"ちいっ……","ENG":"Tch...","TWN":"嘖……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여기서 할 만한 사람이라고는 나랑…….","JPN":"ここでできそうな人と言えば私と……","ENG":"That means it's just me and...","TWN":"現在這裡可以上場的就只有我跟……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"흠흠.","JPN":"おっほん。","ENG":"Ahem!","TWN":"哼哼。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"혹시 내 힘이 필요해?","JPN":"もしかして僕の力が必要かな？","ENG":"Do you need my help?","TWN":"需要我幫忙嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……가자, 쭈구리.","JPN":"……行くよ、弱虫。","ENG":"...Fine. Let's go, squirt.","TWN":"……走吧，泡麵頭。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼 잘 부탁드립니다!","JPN":"それじゃあ、よろしくお願いします！","ENG":"Let's do a good job!","TWN":"那就請多指教囉！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"기세는 좋지만, 너희랑 겨룰 상대는 내가 아니야.","JPN":"威勢が良くて結構だけど、あんたたちと勝負する相手は私じゃないの。","ENG":"Love the determination, but I'm not the one you're going up against.","TWN":"氣勢不錯，但要和你們比的人不是我。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"앗, 설마……?","JPN":"あっ、まさか……？","ENG":"Oh, what...?","TWN":"呃，該不會是……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"바로 이 녀석! 형님에게 술친구를 만들어 드리기 위한 내 역작이다!","JPN":"そう、この子！　兄貴に飲み友達を作ってあげるための私の力作！","ENG":"It's this thing right here! The masterpiece I made so Mr. Haven can have a drinking buddy!","TWN":"就是這傢伙！它可是我專門為大哥打造的酒伴，是我的傑作呢！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아까부터 수영장에서 로봇이 대체 왜 나오는 건데?!","JPN":"さっきからなんでプールからロボットが出てくるんだよ！？","ENG":"Why are there so many robots at this pool?!","TWN":"為什麼游泳池會一直冒出機器人啦？！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"그거야 내가 엔지니어였으니까 그렇지.","JPN":"そりゃあ、私がエンジニアだったからよ。","ENG":"Well, that's because I used to be an engineer.","TWN":"因為我是工程師的嘛。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"옛날부터 기계 만지는 걸 좋아했거든. 내가 네 친구들만한 꼬맹이었을 때부터.","JPN":"昔から機械をいじることが好きだったんだ。あんたの友達くらいのガキだった頃からね。","ENG":"I've always loved to do anything with machines. Ever since I was about the same age as your young friends.","TWN":"我從以前就很喜歡碰機械類的東西，我在你朋友這個年紀時就是這樣。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"저 애들이 차고 있는 보조 장비도 내 손을 거쳤는걸.","JPN":"あの子たちが付けてる補助装備も私が作ったんだから。","ENG":"I even made the equipment those kids are wearing.","TWN":"她們身上的輔助裝備也是出自我之手喔。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"확실히, 실력은 간부라고 할 만하네.","JPN":"確かに、幹部になるだけの実力はあるね。","ENG":"Certainly, her abilities merit the position of a consigliere.","TWN":"確實是名符其實的幹部。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"자, 그럼 대결을 시작해야지.","JPN":"さて、それじゃあ勝負を始めるか。","ENG":"Then, let the game begin.","TWN":"那就開始比賽吧！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"진행자! 술 가져와!","JPN":"司会進行 ！　お酒持って来て！","ENG":"Bring out the booze!","TWN":"主持人！拿酒來！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};